-- Enrichment marathon batch: Papra, Parabola, Paraform, ParagraphAI, Pardot, Parse Platform, Part-DB, Partiful

-- ── Papra ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Papra is an open-source, self-hostable document archiving platform that lets individuals and small teams scan, tag, search and store files under an AGPL-3.0 license, with an optional paid cloud version hosted in Europe.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted); Cloud plans from $7.50/month billed annually$q$, starting_price),
  founded_year = COALESCE(2025, founded_year),
  company_size = COALESCE($q$1 (solo founder, bootstrapped)$q$, company_size),
  headquarters = COALESCE($q$Not publicly disclosed (Europe-based)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Papra Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Papra is an open-source, self-hosted document archiving platform. See features, pricing tiers, pros and cons, and alternatives like Paperless-ngx.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Papra is an open-source, self-hostable document archiving platform created by French developer Corentin Thomasset, who began building it as a side project in January 2025 while employed full time, after finding existing archiving tools like Evernote, Paperless-ngx and enterprise DMS platforms either too complex or not friendly enough for non-technical users. The project is released under the AGPL-3.0 license, is fully open source on GitHub under the papra-hq organization with thousands of stars, and ships as a lightweight Docker image under 200MB, making it easy to run on a home server, NAS, or small VPS. Papra lets individuals and small teams centralize scanned documents, PDFs, receipts and images in one searchable place using organizations, tags, and configurable tagging rules that auto-categorize incoming files; it also supports content extraction (text pulled from images and scans) so documents become full-text searchable, an email-ingestion address that automatically imports anything forwarded to it, and an API, SDK and webhooks for building custom integrations. Unlike most SaaS document managers, Papra offers a true self-hosted option that is free forever because you own the code and your data, alongside an optional managed cloud service hosted in Europe (GDPR-compliant) with Free, Plus ($9/month, or $7.50/month billed annually) and Pro ($30/month, or $25/month billed annually) tiers differentiated mainly by storage, member seats, and upload size limits, plus a custom Enterprise tier. Papra is bootstrapped and independent, explicitly built without venture funding, which shapes its privacy-first positioning ('we never sell your data') and its appeal to privacy-conscious individuals, freelancers, small businesses, and self-hosting or homelab enthusiasts who want an alternative to closed platforms like Evernote or DocuWare. Its closest competitors are Paperless-ngx (another open-source, self-hosted document archiving tool with a similar target audience), DocuWare and M-Files (enterprise document management systems), and Evernote and Notion (general-purpose note and document storage apps that lack Papra's self-hosting and archival focus). Papra is best suited for users who want lightweight, developer-friendly document archiving they fully control, rather than a full enterprise content-management suite; it is less suited to organizations that need deep workflow automation, e-signature, or compliance certifications that larger commercial DMS vendors provide out of the box.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '993944af-a2d6-42bb-a3a0-2b1c8a4c460d';

