-- ── Paraform ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Paraform is an AI-powered recruiting marketplace that connects companies with a network of vetted independent recruiters who compete to fill open roles, paid on a success-fee basis.$q$, short_description),
  pricing_model = COALESCE($q$Custom$q$, pricing_model),
  starting_price = COALESCE($q$Custom (contact sales; recruiters are paid a success-based placement fee)$q$, starting_price),
  founded_year = COALESCE(2023, founded_year),
  company_size = COALESCE($q$51-200 employees (estimate)$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, US$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Paraform Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Paraform is an AI-powered recruiting marketplace connecting companies with vetted recruiters. See how it works, pricing, pros, cons and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Paraform is an AI-powered recruiting marketplace, founded in 2023 by CEO John Kim and CTO Jeffrey Li and headquartered in San Francisco, California, that connects hiring companies with a vetted network of more than 10,000 independent and agency recruiters who compete to fill open roles on a success-fee basis, augmented by custom AI agents that help recruiters source and screen candidates. Rather than a company retaining a single recruiting firm, Paraform lets multiple recruiters work the same open role in parallel; companies post roles on the platform, recruiters opt in to work the ones matching their specialty, and Paraform's software, plus AI sourcing agents that learn a company's hiring preferences over time, helps surface and rank candidates, with the company reporting metrics such as a 70% interview rate and 3x faster time-to-hire on its marketplace. Paraform has raised roughly $65 million in venture funding across a pre-seed round backed by Primer Sazze Partners and Twitch co-founder Kevin Lin, a seed round, a $20 million Series A, and a $40 million Series B in March 2026 led by Scale Venture Partners with participation from Felicis, A* Capital and Liquid 2 Ventures; the company has said it has crossed $100 million in annualized revenue and lists customers including Palantir, Rippling and Abridge. Pricing on Paraform is not published as a flat subscription: companies pay recruiters a placement fee, standard contingency-recruiting economics typically calculated as a percentage of first-year salary, facilitated through the platform, and prospective customers are directed to contact Paraform directly for specifics; the company states it is SOC 2 certified. Paraform's target users are two-sided: fast-growing startups and scaleups, from early-stage to enterprise, that need to fill technical, go-to-market, or specialized roles quickly without building an in-house recruiting team, and independent or boutique recruiters who want a steady pipeline of client roles, AI-assisted sourcing tools, and business-development support rather than cold-prospecting for clients themselves. Its closest competitors include other modern recruiting marketplaces and tech-enabled staffing platforms such as Gem and A.Team, traditional contingency staffing firms like Robert Half, and adjacent sourcing tools such as LinkedIn Recruiter; Paraform differentiates itself by combining a two-sided marketplace model with AI agents embedded directly into the recruiter workflow, aiming to speed up both sourcing and candidate quality relative to traditional single-agency recruiting.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '0abb883b-fe31-411e-a600-34ef2c9cdba6';

