-- ── ParagraphAI ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$ParagraphAI is an AI writing assistant available as iOS and Android apps, a mobile keyboard, and a Chrome extension, letting users generate, fix, reply to and edit text across any app.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (Pro plan from $12.49/month billed annually)$q$, starting_price),
  founded_year = COALESCE(2022, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$Toronto, Ontario, Canada$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$ParagraphAI Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$ParagraphAI is a cross-platform AI writing assistant for mobile and Chrome. Compare features, pricing, pros, cons and alternatives like Grammarly.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$ParagraphAI is an AI writing assistant, founded in 2022 and headquartered in Toronto, Ontario, Canada, that ships as a mobile app for iOS and Android, a custom keyboard, and a Chrome browser extension, letting users generate, edit, reply to, and fix text anywhere they type, in emails, texts, social posts or documents, rather than only inside a dedicated editor. Built by a team the company describes as including engineers with backgrounds at Meta, OpenAI and MIT, ParagraphAI's core functions are labeled Create, Fix, Reply and Edit: Create generates original text from a prompt, Fix corrects grammar and spelling, Reply drafts contextual responses to messages, and Edit adjusts tone, length or phrasing of existing text, with support for more than 40 languages. The product's differentiator versus a browser-only tool like Grammarly is its cross-platform reach through a system-level keyboard and mobile apps, positioning it as an assistant that works inside any app on a phone, not just a web browser or specific editor. ParagraphAI uses a freemium pricing model: a Free plan offers a limited number of daily uses of Create, Fix, Reply and Edit with a 1,000-character input limit, a Pro plan costs $24.99 per month billed monthly or $12.49 per month billed annually (149.99 dollars per year) and unlocks unlimited daily uses, a 10,000-character limit, cross-platform message history and expanded language and rephrasing options, and an Enterprise plan offers custom pricing with brand-voice customization, account management and dedicated support. The company positions its Pro plan as undercutting the annual list price of comparable tools like Grammarly and Wordtune. ParagraphAI's target users are students, professionals and everyday consumers who want quick writing help across texting, email and social apps without switching tools, as well as businesses wanting brand-consistent AI writing support for their teams via the Enterprise tier. Its main competitors are Grammarly, a grammar and writing assistant with a much larger install base and enterprise business, Wordtune, an AI rewriting and tone tool, Jasper, an AI content-generation platform aimed more at marketing teams, and general-purpose chat assistants that can also draft or edit text on request.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f9a72ac4-b017-4bd7-b4fd-5cb3bd343b9e';

