-- ── Pardot ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Pardot is Salesforce's B2B marketing automation platform, officially renamed Marketing Cloud Account Engagement in 2022, offering lead scoring, email nurture campaigns and account-based marketing tightly integrated with Salesforce CRM.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$1,250/month billed annually (Growth plan)$q$, starting_price),
  founded_year = COALESCE(2007, founded_year),
  company_size = COALESCE($q$Division of Salesforce (Salesforce has 70,000+ employees company-wide)$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, US (Salesforce HQ); originally founded in Atlanta, Georgia, US$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Pardot Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Pardot, now Marketing Cloud Account Engagement, is Salesforce's B2B marketing automation tool. Compare pricing, features and HubSpot alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Pardot is a B2B marketing automation platform originally founded in 2007 in Atlanta, Georgia by David Cummings and Adam Blitzer; the name comes from the Latvian word for 'to sell,' discovered via an online dictionary tool when the founders were searching for an available domain. ExactTarget acquired Pardot for roughly $95.5 million in October 2012, and when Salesforce acquired ExactTarget for $2.5 billion in 2013, Pardot became part of the Salesforce Marketing Cloud. In April 2022, Salesforce officially renamed the product Marketing Cloud Account Engagement (MCAE) as part of a broader naming initiative that also touched products like Datorama and Interaction Studio; the underlying platform, APIs, automations, integrations and certifications were unchanged by the rename, and the product is still widely searched for and referred to by its original name, Pardot. As Marketing Cloud Account Engagement, the product remains a B2B-focused marketing automation and account-based marketing tool tightly integrated with Salesforce CRM (Sales Cloud), offering lead scoring and grading, email marketing and nurture campaigns, landing pages and forms, ROI reporting, and account-based marketing features for aligning sales and marketing teams around target accounts. Pricing is subscription-based with four published tiers: Growth at $1,250/month, Plus at $2,500/month, Advanced at $4,000/month, and Premium at $15,000/month, all billed annually and priced per organization rather than per user, with optional add-ons such as Salesforce Engage ($50/user/month) for sales teams and B2B Marketing Analytics Plus (around $3,000/month) for advanced reporting. Because it requires a Salesforce CRM connection and carries enterprise-level pricing, Pardot/MCAE is aimed at mid-market and enterprise B2B marketing teams already invested in the Salesforce ecosystem, rather than small businesses or B2C marketers. Its primary competitors are HubSpot Marketing Hub, a more SMB-friendly, all-in-one alternative, Adobe Marketo Engage, a comparable enterprise B2B automation platform, and Oracle Eloqua; Pardot/MCAE's core differentiator is its native, deep integration with Salesforce Sales Cloud for account-based marketing and sales-marketing alignment, making it the default choice for organizations that have already standardized on Salesforce as their CRM.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c2c65cc7-4f96-4e51-91e3-3da83872e2cd';

