-- ── Part-DB ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Part-DB is a free, open-source inventory management system for electronic components, letting makers, hackerspaces and small hardware teams track parts, stock locations, datasheets and bills of materials.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE($q$Not applicable (open-source project maintained by a small volunteer team)$q$, company_size),
  headquarters = COALESCE($q$Not publicly disclosed (primary maintainer based in Germany)$q$, headquarters),
  languages = ARRAY[$q$German$q$, $q$English$q$, $q$Russian$q$, $q$Japanese$q$, $q$French$q$, $q$Czech$q$, $q$Danish$q$, $q$Chinese$q$]::text[],
  seo_title = COALESCE($q$Part-DB Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Part-DB is a free, open-source inventory system for electronic parts. See features, self-hosting setup, pros, cons and alternatives like InvenTree.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Part-DB is a free, open-source inventory and parts management system built specifically for electronic components, designed for hobbyists, makerspaces, small hardware companies and universities that need to track parts, footprints, manufacturers, storage locations, pricing and datasheets in one searchable web application. The current actively maintained version, Part-DB-server, is built on PHP (Symfony 7, requiring PHP 8.2 or newer) with support for MySQL, MariaDB, PostgreSQL or SQLite databases, is distributed as a Docker image, and is developed primarily by Jan Bohmer (GitHub handle jbtronics), succeeding an earlier legacy PHP/MySQL version of the project first documented publicly around 2016; the software is licensed under the GNU Affero General Public License v3.0 (AGPL-3.0), meaning it can be used commercially but any modified, publicly served version must have its source code published. Functionally, Part-DB lets users catalog electronic parts with categories, footprints, manufacturers, multiple stock locations and price-break information, attach datasheets and images to each part, generate barcodes and printable labels for parts and storage bins, and build projects that assign parts to a bill of materials (BOM) for tracking what's needed or used in a build. It includes a user and permissions system with groups and granular access control, two-factor authentication (Google Authenticator and WebAuthn/U2F hardware keys), a responsive interface usable on desktop, tablet or phone, and multi-language support across at least eight languages including German, English, Russian, Japanese, French, Czech, Danish and Chinese, reflecting its origins and strong userbase in the German maker and electronics community. There is no commercial pricing tier, Part-DB is entirely free to self-host, with no official SaaS offering, and revenue or monetization is not part of the project's model; it relies on volunteer maintenance and community contributions on GitHub. Part-DB is aimed squarely at technical, self-hosting-comfortable users: electronics hobbyists managing personal component stashes, hackerspaces and makerspaces coordinating shared inventories among many members, and small electronics or hardware engineering teams that need lightweight parts tracking without the cost or complexity of full enterprise PLM/ERP systems. Its closest alternatives include InvenTree, another open-source, self-hosted parts and stock management system popular for hardware and manufacturing use cases, Binner, an open-source parts inventory tool for makers and engineers, and general-purpose inventory tools like Odoo Inventory or spreadsheet-based tracking, which Part-DB is usually chosen over specifically because of its purpose-built focus on electronic component metadata like footprints, datasheets and manufacturer part numbers.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '22f25c2f-1b4c-48c2-90e3-6d5df186e020';

UPDATE tools SET logo = 'https://www.google.com/s2/favicons?domain=' || regexp_replace(regexp_replace(website, '^https?://', ''), '/.*$', '') || '&sz=256' WHERE id = '22f25c2f-1b4c-48c2-90e3-6d5df186e020' AND logo IS NULL AND website IS NOT NULL;

