INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('993944af-a2d6-42bb-a3a0-2b1c8a4c460d', $q$Self-hosting via Docker$q$, $q$Run Papra on your own server or NAS with a lightweight (under 200MB) Docker image, keeping full control of your data.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('993944af-a2d6-42bb-a3a0-2b1c8a4c460d', $q$Email ingestion$q$, $q$Forward emails and attachments to a generated address to automatically archive documents without manual uploads.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('993944af-a2d6-42bb-a3a0-2b1c8a4c460d', $q$Automatic tagging rules$q$, $q$Create custom rules that tag and organize incoming documents automatically based on content or source.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('993944af-a2d6-42bb-a3a0-2b1c8a4c460d', $q$Full-text content extraction$q$, $q$Text is automatically extracted from scanned images and PDFs so every document becomes searchable.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('993944af-a2d6-42bb-a3a0-2b1c8a4c460d', $q$Organizations and teams$q$, $q$Group documents under organizations with member roles, useful for households, freelancers or small businesses.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('993944af-a2d6-42bb-a3a0-2b1c8a4c460d', $q$API, SDK and webhooks$q$, $q$Build custom integrations and automations on top of Papra using its developer-facing API and webhook system.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('993944af-a2d6-42bb-a3a0-2b1c8a4c460d', $q$European cloud hosting$q$, $q$Optional managed cloud plans store data in Europe under GDPR-compliant infrastructure.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('993944af-a2d6-42bb-a3a0-2b1c8a4c460d', $q$Free and fully open source (AGPL-3.0) with no vendor lock-in$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('993944af-a2d6-42bb-a3a0-2b1c8a4c460d', $q$Lightweight self-hosting footprint compared to heavier enterprise DMS platforms$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('993944af-a2d6-42bb-a3a0-2b1c8a4c460d', $q$Automatic tagging and email ingestion reduce manual filing work$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('993944af-a2d6-42bb-a3a0-2b1c8a4c460d', $q$Transparent, low-cost managed cloud option for non-technical users$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('993944af-a2d6-42bb-a3a0-2b1c8a4c460d', $q$Actively developed with a public roadmap and responsive open-source community$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('993944af-a2d6-42bb-a3a0-2b1c8a4c460d', $q$Young project (started 2025) so its feature set and integrations are less mature than established DMS platforms$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('993944af-a2d6-42bb-a3a0-2b1c8a4c460d', $q$Self-hosting requires basic Docker and server administration skills$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('993944af-a2d6-42bb-a3a0-2b1c8a4c460d', $q$No dedicated native mobile app is documented at this time$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('993944af-a2d6-42bb-a3a0-2b1c8a4c460d', $q$Smaller ecosystem of third-party integrations than SaaS incumbents like Evernote$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('993944af-a2d6-42bb-a3a0-2b1c8a4c460d', $q$Enterprise-grade compliance certifications (such as SOC 2 or HIPAA) are not publicly documented$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('993944af-a2d6-42bb-a3a0-2b1c8a4c460d', $q$Is Papra free?$q$, $q$Yes, self-hosting Papra is free forever since it is open source; a paid managed cloud service is also available starting at $9/month.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('993944af-a2d6-42bb-a3a0-2b1c8a4c460d', $q$Is Papra open source?$q$, $q$Yes, Papra is released under the AGPL-3.0 license and hosted publicly on GitHub.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('993944af-a2d6-42bb-a3a0-2b1c8a4c460d', $q$Who makes Papra?$q$, $q$Independent developer Corentin Thomasset, who built and bootstrapped it without venture funding.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('993944af-a2d6-42bb-a3a0-2b1c8a4c460d', $q$Can I self-host Papra?$q$, $q$Yes, via a lightweight Docker image on your own server or NAS.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('993944af-a2d6-42bb-a3a0-2b1c8a4c460d', $q$Does Papra support OCR-style text extraction?$q$, $q$Yes, it automatically extracts text from images and scanned documents so they become searchable.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('993944af-a2d6-42bb-a3a0-2b1c8a4c460d', $q$How is Papra different from Paperless-ngx?$q$, $q$Both are open-source, self-hosted document archivers; Papra adds tagging rules, email ingestion, an optional managed cloud plan, and an API/SDK out of the box.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('993944af-a2d6-42bb-a3a0-2b1c8a4c460d', $q$Where is Papra's cloud data hosted?$q$, $q$In Europe, on GDPR-compliant infrastructure.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('993944af-a2d6-42bb-a3a0-2b1c8a4c460d', $q$Does Papra have an API?$q$, $q$Yes, along with an SDK and webhooks for custom integrations.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('993944af-a2d6-42bb-a3a0-2b1c8a4c460d', $q$Personal document archiving$q$, $q$Individuals scan and store receipts, contracts, IDs and other personal paperwork in one searchable place.$q$, $q$Privacy-conscious individuals and families$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('993944af-a2d6-42bb-a3a0-2b1c8a4c460d', $q$Small business and freelancer paperwork$q$, $q$Freelancers and small businesses organize invoices, contracts and receipts without a full enterprise DMS.$q$, $q$Freelancers and small business owners$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('993944af-a2d6-42bb-a3a0-2b1c8a4c460d', $q$Self-hosted homelab document hub$q$, $q$Technical users run Papra alongside other self-hosted services on a home server or NAS.$q$, $q$Self-hosting and homelab enthusiasts$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('993944af-a2d6-42bb-a3a0-2b1c8a4c460d', $q$Free (Cloud)$q$, $q$$0/month$q$, $q$Monthly$q$, NULL, $q$["512MB storage (about 4,000 PDFs)","3 members per organization","25MB max upload size","1 intake email address","Basic support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('993944af-a2d6-42bb-a3a0-2b1c8a4c460d', $q$Plus (Cloud)$q$, $q$$9/month ($7.50/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["5GB storage (about 20,000 PDFs)","10 members per organization","100MB max upload size","10 intake email addresses","Priority support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('993944af-a2d6-42bb-a3a0-2b1c8a4c460d', $q$Pro (Cloud)$q$, $q$$30/month ($25/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["50GB storage (about 200,000 PDFs)","50 members per organization","500MB max upload size","100 intake email addresses","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('993944af-a2d6-42bb-a3a0-2b1c8a4c460d', $q$Self-Hosted$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full open-source AGPL-3.0 codebase","Run on your own infrastructure","No storage limits beyond your own hardware"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('993944af-a2d6-42bb-a3a0-2b1c8a4c460d', $q$Enterprise$q$, $q$Custom (contact sales)$q$, $q$Custom$q$, NULL, $q$["Tailored storage and member limits","Advanced features on request","Dedicated support"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('993944af-a2d6-42bb-a3a0-2b1c8a4c460d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Papra is an open-source document archiving and management platform built for people who want to organize scanned documents, PDFs, receipts and images without handing their data to a closed SaaS vendor. It was started in January 2025 by independent developer Corentin Thomasset as a side project, and has since grown into a full product with thousands of GitHub stars, released entirely under the AGPL-3.0 license.$q$, $q$The platform ships as a lightweight Docker image (under 200MB), so it can run on a home server, NAS, or inexpensive VPS with minimal resources. For people who don't want to manage their own infrastructure, Papra also offers an optional managed cloud service hosted in Europe under GDPR-compliant infrastructure.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('993944af-a2d6-42bb-a3a0-2b1c8a4c460d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Documents in Papra are organized using organizations (useful for teams, households or companies), free-form tags, and automated tagging rules that categorize incoming files based on custom conditions. Content extraction automatically pulls text out of scanned images and PDFs, so every archived document becomes searchable rather than just stored.$q$, $q$An email-ingestion address lets users forward emails and attachments directly into their archive without manual uploads, while an API, SDK and webhook system make it possible to build custom integrations or automate document intake from other tools.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('993944af-a2d6-42bb-a3a0-2b1c8a4c460d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Self-hosting Papra is free forever since the code is fully open source; users only pay for their own server or storage costs. For those who prefer not to self-host, Papra's managed cloud plans start with a Free tier (512MB storage, 3 members) and scale up through Plus ($9/month, or $7.50/month billed annually) and Pro ($30/month, or $25/month billed annually) tiers based on storage, member seats and upload limits.$q$, $q$A custom Enterprise tier is available for organizations with larger or more specific requirements, with pricing available on request. Annual billing on cloud plans saves roughly 20% compared to paying monthly.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('993944af-a2d6-42bb-a3a0-2b1c8a4c460d', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
