INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('812e6387-746a-402d-9db8-ecb8da116b61', $q$Visual workflow canvas$q$, $q$Drag-and-drop steps to import, clean, transform and route data without writing code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('812e6387-746a-402d-9db8-ecb8da116b61', $q$Broad data source support$q$, $q$Pull data from spreadsheets, email attachments, PDFs, APIs and databases into a single flow.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('812e6387-746a-402d-9db8-ecb8da116b61', $q$AI agent builder$q$, $q$Describe a task in plain language and have an AI agent assemble the corresponding workflow.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('812e6387-746a-402d-9db8-ecb8da116b61', $q$Scheduled automation$q$, $q$Run flows automatically on a recurring schedule, with more frequent intervals on higher tiers.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('812e6387-746a-402d-9db8-ecb8da116b61', $q$Built-in dashboards and visualizations$q$, $q$Turn processed data into charts, tables and dashboards directly inside Parabola.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('812e6387-746a-402d-9db8-ecb8da116b61', $q$Enterprise controls$q$, $q$Role-based access, SSO, SOC 2 Type II compliance and audit trails on Business and Enterprise plans.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('812e6387-746a-402d-9db8-ecb8da116b61', $q$Template library$q$, $q$Pre-built flows for common ecommerce, retail and logistics data-automation use cases.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('812e6387-746a-402d-9db8-ecb8da116b61', $q$No-code visual builder handles messy, unstructured data such as PDFs and mismatched spreadsheets better than typical integration tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('812e6387-746a-402d-9db8-ecb8da116b61', $q$AI agent builder lowers the barrier for describing workflows in plain language$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('812e6387-746a-402d-9db8-ecb8da116b61', $q$Strong fit for ecommerce, retail and logistics data-reconciliation use cases$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('812e6387-746a-402d-9db8-ecb8da116b61', $q$Scheduled automation removes recurring manual spreadsheet work$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('812e6387-746a-402d-9db8-ecb8da116b61', $q$Enterprise-grade security and access controls available on Business and Enterprise plans$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('812e6387-746a-402d-9db8-ecb8da116b61', $q$Public pricing beyond the free tier is limited; paid and Business-tier costs typically require contacting sales$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('812e6387-746a-402d-9db8-ecb8da116b61', $q$Usage-based step or credit limits can become expensive at high volume$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('812e6387-746a-402d-9db8-ecb8da116b61', $q$Steeper learning curve than simple point-and-click automations for complex, multi-step flows$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('812e6387-746a-402d-9db8-ecb8da116b61', $q$Primarily built for batch/scheduled data processing rather than real-time streaming data$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('812e6387-746a-402d-9db8-ecb8da116b61', $q$Smaller integration marketplace than category leaders like Zapier or Make$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('812e6387-746a-402d-9db8-ecb8da116b61', $q$What is Parabola used for?$q$, $q$Automating recurring data-wrangling tasks such as consolidating spreadsheets, reconciling orders, or generating reports without writing code.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('812e6387-746a-402d-9db8-ecb8da116b61', $q$Is Parabola free?$q$, $q$Yes, there is a free plan with limited flows and monthly processing steps; paid Business and Enterprise plans add higher limits and enterprise features.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('812e6387-746a-402d-9db8-ecb8da116b61', $q$Does Parabola require coding?$q$, $q$No, it is a no-code visual platform, though it also offers an AI agent builder for plain-language workflow creation.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('812e6387-746a-402d-9db8-ecb8da116b61', $q$Who uses Parabola?$q$, $q$Operations, RevOps, ecommerce, retail, freight and logistics, and finance teams at small and mid-market companies.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('812e6387-746a-402d-9db8-ecb8da116b61', $q$What data sources does Parabola support?$q$, $q$Spreadsheets, email attachments, PDFs, APIs, databases and many common business tools.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('812e6387-746a-402d-9db8-ecb8da116b61', $q$Is Parabola SOC 2 compliant?$q$, $q$Business and Enterprise plans include SOC 2 Type II compliance and audit trails.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('812e6387-746a-402d-9db8-ecb8da116b61', $q$How is Parabola different from Zapier?$q$, $q$Parabola focuses on transforming and reshaping messy, semi-structured business data through a visual canvas, while Zapier focuses on simple trigger-action integrations between apps.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('812e6387-746a-402d-9db8-ecb8da116b61', $q$Can Parabola flows run on a schedule?$q$, $q$Yes, flows can be scheduled to run automatically, with more frequent scheduling available on higher-tier plans.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('812e6387-746a-402d-9db8-ecb8da116b61', $q$Ecommerce order and inventory reconciliation$q$, $q$Automatically pull, clean and reconcile order and inventory data across platforms like Shopify.$q$, $q$Ecommerce operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('812e6387-746a-402d-9db8-ecb8da116b61', $q$Freight and logistics invoice consolidation$q$, $q$Consolidate vendor freight invoices and shipment data into a single automated report.$q$, $q$Supply chain and logistics teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('812e6387-746a-402d-9db8-ecb8da116b61', $q$Recurring reporting and dashboard automation$q$, $q$Automate the creation of recurring reports and dashboards from scattered data sources.$q$, $q$RevOps and finance teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('812e6387-746a-402d-9db8-ecb8da116b61', $q$Free$q$, $q$$0/month$q$, $q$Monthly$q$, NULL, $q$["1 user","Up to 3 flows","200 processed steps per month","Data visualizations","10,000-row data storage"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('812e6387-746a-402d-9db8-ecb8da116b61', $q$Business$q$, $q$Custom (contact sales)$q$, $q$Custom$q$, NULL, $q$["AI agent builder for describing workflows in plain language","Live training and deployment support","Proof of concept with production data","Native integrations at scale"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('812e6387-746a-402d-9db8-ecb8da116b61', $q$Enterprise$q$, $q$Custom (contact sales)$q$, $q$Custom$q$, NULL, $q$["Role-based access controls","Version history and rollback","SSO and SOC 2 Type II compliance","Audit trails and SLA-backed uptime","Dedicated account manager"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('812e6387-746a-402d-9db8-ecb8da116b61', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Parabola is a no-code data workflow automation platform aimed at operations, ecommerce, logistics and finance teams that spend hours each week manually wrangling spreadsheets, vendor files, PDFs and emails. Founded in 2017 and based in San Francisco, the company built its product around a visual canvas where users connect steps rather than write scripts.$q$, $q$More recently, Parabola has added an AI agent builder that lets users describe a workflow in plain language and have it assembled automatically, reflecting a broader shift toward AI-assisted automation for operations teams that don't have dedicated engineering support.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('812e6387-746a-402d-9db8-ecb8da116b61', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its core, Parabola pulls data from spreadsheets, email attachments, PDFs, APIs and business tools, then lets users clean, merge, filter and reshape that data through a drag-and-drop sequence of steps, without writing code. Processed data can be turned into charts, tables and dashboards, or routed automatically to destinations like Slack, email, Google Sheets or other software.$q$, $q$Flows can run on a recurring schedule so recurring reports and reconciliations happen automatically. Business and Enterprise plans add role-based access control, SSO, SOC 2 Type II compliance, audit trails, and dedicated account support for larger teams with security and governance requirements.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('812e6387-746a-402d-9db8-ecb8da116b61', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Parabola uses a freemium model. The Free plan includes 1 user, up to 3 flows, 200 processed steps per month, data visualizations, and storage for up to 10,000 rows, making it usable for individuals or very small teams testing the platform.$q$, $q$Beyond the free tier, Parabola offers Business and Enterprise plans with custom, volume-based pricing that requires contacting sales; these unlock higher step allowances, unlimited data storage, more frequent scheduling, and enterprise security and support features.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('812e6387-746a-402d-9db8-ecb8da116b61', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0abb883b-fe31-411e-a600-34ef2c9cdba6', $q$Two-sided recruiter marketplace$q$, $q$Companies post roles that a network of 10,000+ vetted recruiters can opt into and work in parallel.$q$, 0);
