INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0abb883b-fe31-411e-a600-34ef2c9cdba6', $q$Talent strategist support$q$, $q$Dedicated talent strategists provide guidance to hiring teams throughout the search.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0abb883b-fe31-411e-a600-34ef2c9cdba6', $q$Performance-based pricing$q$, $q$Companies pay recruiters a placement fee only when a role is successfully filled.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0abb883b-fe31-411e-a600-34ef2c9cdba6', $q$SOC 2 certification$q$, $q$Enterprise-grade security compliance for handling candidate and company data.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0abb883b-fe31-411e-a600-34ef2c9cdba6', $q$Multiple recruiters can work the same role in parallel, increasing candidate pipeline speed$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0abb883b-fe31-411e-a600-34ef2c9cdba6', $q$AI agents assist with sourcing and screening, reducing manual recruiter workload$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0abb883b-fe31-411e-a600-34ef2c9cdba6', $q$No upfront subscription cost for companies; they pay only on successful placement$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0abb883b-fe31-411e-a600-34ef2c9cdba6', $q$Access to a large, pre-vetted network of specialized recruiters$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0abb883b-fe31-411e-a600-34ef2c9cdba6', $q$Backed by well-known investors and reporting fast revenue growth as of 2026$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0abb883b-fe31-411e-a600-34ef2c9cdba6', $q$Pricing is not transparent; understanding fee structure requires contacting sales$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0abb883b-fe31-411e-a600-34ef2c9cdba6', $q$Success-fee/contingency pricing can be more expensive per hire than in-house recruiting at scale$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0abb883b-fe31-411e-a600-34ef2c9cdba6', $q$Marketplace quality depends on which recruiters opt into a given role$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0abb883b-fe31-411e-a600-34ef2c9cdba6', $q$Best suited to startups and scaleups; less proven for large enterprise-wide recruiting programs$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0abb883b-fe31-411e-a600-34ef2c9cdba6', $q$Relatively young company (founded 2023) with a shorter track record than legacy staffing firms$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0abb883b-fe31-411e-a600-34ef2c9cdba6', $q$What is Paraform?$q$, $q$An AI-powered recruiting marketplace connecting companies with independent recruiters who compete to fill open roles.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0abb883b-fe31-411e-a600-34ef2c9cdba6', $q$How does Paraform pricing work?$q$, $q$Companies do not pay a flat subscription; recruiters are paid a placement fee when they successfully fill a role, and exact terms require contacting Paraform.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0abb883b-fe31-411e-a600-34ef2c9cdba6', $q$Who founded Paraform?$q$, $q$John Kim (CEO) and Jeffrey Li (CTO) founded the company in 2023.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0abb883b-fe31-411e-a600-34ef2c9cdba6', $q$How much funding has Paraform raised?$q$, $q$Approximately $65 million total, including a $40 million Series B led by Scale Venture Partners in March 2026.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0abb883b-fe31-411e-a600-34ef2c9cdba6', $q$Who uses Paraform?$q$, $q$Startups and scaleups seeking to fill technical, go-to-market and specialized roles, plus independent recruiters seeking client work.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0abb883b-fe31-411e-a600-34ef2c9cdba6', $q$Does Paraform use AI?$q$, $q$Yes, custom AI agents help recruiters source and screen candidates and learn a company's hiring preferences over time.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0abb883b-fe31-411e-a600-34ef2c9cdba6', $q$Is Paraform only for tech companies?$q$, $q$Its customer base leans toward startups and tech companies, though the marketplace covers a range of role types.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0abb883b-fe31-411e-a600-34ef2c9cdba6', $q$Is Paraform SOC 2 certified?$q$, $q$Yes, according to the company.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0abb883b-fe31-411e-a600-34ef2c9cdba6', $q$Startup engineering and go-to-market hiring$q$, $q$Fast-growing startups fill technical and go-to-market roles quickly using the recruiter marketplace.$q$, $q$Startup founders and talent teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0abb883b-fe31-411e-a600-34ef2c9cdba6', $q$Recruiter client pipeline$q$, $q$Independent recruiters access a steady stream of client roles and AI-assisted sourcing tools.$q$, $q$Independent and boutique recruiters$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0abb883b-fe31-411e-a600-34ef2c9cdba6', $q$Scaleup specialized hiring$q$, $q$Companies fill niche or hard-to-source roles without building a large internal recruiting org.$q$, $q$Scaleup HR and talent leaders$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0abb883b-fe31-411e-a600-34ef2c9cdba6', $q$Companies$q$, $q$Custom (contact sales)$q$, $q$Per successful placement$q$, NULL, $q$["Success-fee pricing, pay only when a role is filled","Access to 10,000+ vetted recruiters","AI sourcing and screening agents","Dedicated talent strategist support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0abb883b-fe31-411e-a600-34ef2c9cdba6', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Paraform is a recruiting marketplace founded in 2023 that pairs companies with a large network of independent recruiters, rather than routing hiring through a single agency. Companies post open roles, and recruiters who specialize in that type of hiring opt in to work them, often with several recruiters competing for the same role at once.$q$, $q$The San Francisco-based company layers AI agents on top of this marketplace to help recruiters source and screen candidates faster, and has grown quickly, reporting more than $100 million in annualized revenue and backing from investors including Scale Venture Partners, Felicis and early Twitch co-founder Kevin Lin.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0abb883b-fe31-411e-a600-34ef2c9cdba6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Paraform's marketplace gives companies access to more than 10,000 vetted recruiters across different specialties, and its AI sourcing agents learn a company's hiring preferences over time to improve candidate matching. Dedicated talent strategists provide additional guidance to hiring teams alongside the self-serve marketplace tools.$q$, $q$Because pricing is success-based, companies only pay recruiters when a role is actually filled, rather than paying retainers or subscription fees up front. Paraform reports high performance metrics such as a 70% interview rate and 3x faster hiring compared to traditional recruiting.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0abb883b-fe31-411e-a600-34ef2c9cdba6', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Paraform does not publish flat subscription pricing. Instead, companies pay recruiters a placement fee, standard contingency-recruiting economics, when a role is successfully filled through the platform, and specific fee structures are discussed directly with Paraform's sales team.$q$, $q$This model means there is no upfront cost for companies to post roles and access the recruiter network, but overall cost per hire depends on the negotiated placement fee for each role and recruiter.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9a72ac4-b017-4bd7-b4fd-5cb3bd343b9e', $q$Cross-platform coverage$q$, $q$Available as iOS and Android apps, a mobile keyboard, and a Chrome extension.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9a72ac4-b017-4bd7-b4fd-5cb3bd343b9e', $q$Create$q$, $q$Generate original text on any topic from a short prompt.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9a72ac4-b017-4bd7-b4fd-5cb3bd343b9e', $q$Fix$q$, $q$Instantly correct grammar, spelling and punctuation.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9a72ac4-b017-4bd7-b4fd-5cb3bd343b9e', $q$Reply$q$, $q$Draft contextual responses to messages and emails.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9a72ac4-b017-4bd7-b4fd-5cb3bd343b9e', $q$Edit$q$, $q$Adjust the tone, length and phrasing of existing text.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9a72ac4-b017-4bd7-b4fd-5cb3bd343b9e', $q$40+ language support$q$, $q$Write and edit in more than 40 languages.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f9a72ac4-b017-4bd7-b4fd-5cb3bd343b9e', $q$Brand voice customization$q$, $q$Enterprise plans can tailor tone and style to a company's brand for team-wide use.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f9a72ac4-b017-4bd7-b4fd-5cb3bd343b9e', $q$Works across mobile apps and the browser via a keyboard and extension, not just a single editor$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f9a72ac4-b017-4bd7-b4fd-5cb3bd343b9e', $q$Simple four-function model (Create, Fix, Reply, Edit) is easy to learn$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f9a72ac4-b017-4bd7-b4fd-5cb3bd343b9e', $q$Annual Pro pricing undercuts some comparable writing assistants$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f9a72ac4-b017-4bd7-b4fd-5cb3bd343b9e', $q$Broad language support (40+) for non-English writers$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f9a72ac4-b017-4bd7-b4fd-5cb3bd343b9e', $q$Free plan available to try core features before upgrading$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f9a72ac4-b017-4bd7-b4fd-5cb3bd343b9e', $q$Free plan is limited to a small number of daily uses and a 1,000-character cap$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f9a72ac4-b017-4bd7-b4fd-5cb3bd343b9e', $q$Smaller brand recognition and integration ecosystem than Grammarly$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f9a72ac4-b017-4bd7-b4fd-5cb3bd343b9e', $q$Enterprise pricing is not publicly disclosed$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f9a72ac4-b017-4bd7-b4fd-5cb3bd343b9e', $q$Character limits even on Pro (10,000) may constrain long-form writing use cases$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f9a72ac4-b017-4bd7-b4fd-5cb3bd343b9e', $q$Keyboard-based mobile writing tools can raise data-privacy considerations for sensitive text$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f9a72ac4-b017-4bd7-b4fd-5cb3bd343b9e', $q$Is ParagraphAI free?$q$, $q$Yes, a free plan is available with limited daily uses of its Create, Fix, Reply and Edit tools.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f9a72ac4-b017-4bd7-b4fd-5cb3bd343b9e', $q$How much does ParagraphAI Pro cost?$q$, $q$$24.99/month billed monthly, or $12.49/month billed annually ($149.88/year).$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f9a72ac4-b017-4bd7-b4fd-5cb3bd343b9e', $q$What platforms does ParagraphAI support?$q$, $q$iOS, Android, a mobile keyboard, and a Chrome browser extension.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f9a72ac4-b017-4bd7-b4fd-5cb3bd343b9e', $q$How many languages does ParagraphAI support?$q$, $q$More than 40 languages.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f9a72ac4-b017-4bd7-b4fd-5cb3bd343b9e', $q$Who founded ParagraphAI?$q$, $q$The company was founded in 2022 and is based in Toronto, Ontario, Canada.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f9a72ac4-b017-4bd7-b4fd-5cb3bd343b9e', $q$Is there a ParagraphAI Enterprise plan?$q$, $q$Yes, with custom pricing, brand-voice customization and dedicated account support.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f9a72ac4-b017-4bd7-b4fd-5cb3bd343b9e', $q$How is ParagraphAI different from Grammarly?$q$, $q$ParagraphAI emphasizes cross-platform mobile use via a keyboard and native apps, while Grammarly is primarily browser and desktop-focused with a larger enterprise offering.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f9a72ac4-b017-4bd7-b4fd-5cb3bd343b9e', $q$Does ParagraphAI have a character limit?$q$, $q$Yes, 1,000 characters on Free and 10,000 characters on Pro.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f9a72ac4-b017-4bd7-b4fd-5cb3bd343b9e', $q$Everyday mobile writing help$q$, $q$Texting, email and social replies polished on the go from a phone keyboard.$q$, $q$Students and general consumers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f9a72ac4-b017-4bd7-b4fd-5cb3bd343b9e', $q$Professional email and business writing$q$, $q$Drafting and polishing work correspondence quickly across apps.$q$, $q$Professionals and knowledge workers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f9a72ac4-b017-4bd7-b4fd-5cb3bd343b9e', $q$Brand-consistent team writing$q$, $q$Enterprise brand-voice customization keeps team writing on-tone.$q$, $q$Businesses and marketing teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f9a72ac4-b017-4bd7-b4fd-5cb3bd343b9e', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["5 uses/day each of Create, Fix, Reply and Edit","1,000 character limit","40+ language support","Basic keyboard functions"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f9a72ac4-b017-4bd7-b4fd-5cb3bd343b9e', $q$Pro$q$, $q$$24.99/month billed monthly, or $12.49/month billed annually ($149.88/year)$q$, $q$Monthly or annual$q$, NULL, $q$["Unlimited daily uses of Create, Fix, Reply and Edit","10,000 character limit","Cross-platform message history","Expanded rephrasing and length options"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f9a72ac4-b017-4bd7-b4fd-5cb3bd343b9e', $q$Enterprise$q$, $q$Custom (contact sales)$q$, $q$Custom$q$, NULL, $q$["All Pro features","Brand voice customization","Account management tools","Dedicated account representative and 24/7 support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f9a72ac4-b017-4bd7-b4fd-5cb3bd343b9e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ParagraphAI is an AI writing assistant founded in 2022 and based in Toronto, Ontario, Canada. Unlike browser-only writing tools, it ships as native iOS and Android apps, a system-level mobile keyboard, and a Chrome extension, so it can assist with writing inside virtually any app on a phone or in the browser.$q$, $q$The company describes its team as including engineers with backgrounds at Meta, OpenAI and MIT, and built the product around four core actions: Create, Fix, Reply and Edit, aimed at making everyday writing on mobile devices faster and more polished.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f9a72ac4-b017-4bd7-b4fd-5cb3bd343b9e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Create generates original text from a short prompt, Fix instantly corrects grammar, spelling and punctuation, Reply drafts contextual responses to messages and emails, and Edit adjusts the tone, length or phrasing of existing text. These functions are available across the mobile apps, keyboard and Chrome extension, and support more than 40 languages.$q$, $q$An Enterprise tier adds brand-voice customization, letting companies tailor tone and style for consistent team-wide writing, along with dedicated account management and support.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f9a72ac4-b017-4bd7-b4fd-5cb3bd343b9e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$ParagraphAI's Free plan includes 5 uses per day each of Create, Fix, Reply and Edit, with a 1,000-character input limit. The Pro plan costs $24.99 per month billed monthly, or $12.49 per month billed annually ($149.88/year), and removes daily usage caps while raising the character limit to 10,000.$q$, $q$An Enterprise plan is available with custom pricing for organizations that need brand-voice customization, account management, and dedicated support across a team.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c2c65cc7-4f96-4e51-91e3-3da83872e2cd', $q$Lead scoring and grading$q$, $q$Automatically rank leads by engagement and fit to prioritize sales follow-up.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c2c65cc7-4f96-4e51-91e3-3da83872e2cd', $q$Email marketing and nurture campaigns$q$, $q$Build automated drip and nurture email sequences for prospects.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c2c65cc7-4f96-4e51-91e3-3da83872e2cd', $q$Native Salesforce CRM integration$q$, $q$Deep, bidirectional sync with Salesforce Sales Cloud.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c2c65cc7-4f96-4e51-91e3-3da83872e2cd', $q$Landing pages and forms$q$, $q$Build and test forms and landing pages without a developer.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c2c65cc7-4f96-4e51-91e3-3da83872e2cd', $q$Account-based marketing (ABM)$q$, $q$Target and report on named accounts, aligning sales and marketing.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c2c65cc7-4f96-4e51-91e3-3da83872e2cd', $q$ROI and campaign reporting$q$, $q$Attribute pipeline and revenue back to marketing campaigns.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c2c65cc7-4f96-4e51-91e3-3da83872e2cd', $q$Engagement Studio$q$, $q$Visual automation builder for multi-step nurture journeys.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c2c65cc7-4f96-4e51-91e3-3da83872e2cd', $q$Deep, native integration with Salesforce Sales Cloud CRM$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c2c65cc7-4f96-4e51-91e3-3da83872e2cd', $q$Strong lead scoring and grading plus account-based marketing features for B2B teams$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c2c65cc7-4f96-4e51-91e3-3da83872e2cd', $q$Mature, enterprise-proven platform with a long track record originally launched in 2007$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c2c65cc7-4f96-4e51-91e3-3da83872e2cd', $q$Engagement Studio provides robust visual automation for nurture journeys$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c2c65cc7-4f96-4e51-91e3-3da83872e2cd', $q$Backed by Salesforce's broader ecosystem of apps, partners and AppExchange integrations$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c2c65cc7-4f96-4e51-91e3-3da83872e2cd', $q$Enterprise pricing starting at $1,250/month billed annually is out of reach for small businesses$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c2c65cc7-4f96-4e51-91e3-3da83872e2cd', $q$Requires a Salesforce CRM license to get full value, adding to total cost$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c2c65cc7-4f96-4e51-91e3-3da83872e2cd', $q$Steeper learning curve and implementation timeline than SMB-focused tools like HubSpot$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c2c65cc7-4f96-4e51-91e3-3da83872e2cd', $q$Per-organization (not per-user) pricing model can be less flexible for smaller teams$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c2c65cc7-4f96-4e51-91e3-3da83872e2cd', $q$Brand confusion persists from the 2022 rename to Marketing Cloud Account Engagement$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c2c65cc7-4f96-4e51-91e3-3da83872e2cd', $q$Is Pardot the same as Marketing Cloud Account Engagement?$q$, $q$Yes, Salesforce renamed Pardot to Marketing Cloud Account Engagement in April 2022; the underlying product is unchanged.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c2c65cc7-4f96-4e51-91e3-3da83872e2cd', $q$How much does Pardot cost?$q$, $q$Published tiers are Growth at $1,250/month, Plus at $2,500/month, Advanced at $4,000/month and Premium at $15,000/month, billed annually.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c2c65cc7-4f96-4e51-91e3-3da83872e2cd', $q$Who founded Pardot?$q$, $q$David Cummings and Adam Blitzer founded Pardot in 2007 in Atlanta, Georgia.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c2c65cc7-4f96-4e51-91e3-3da83872e2cd', $q$Does Pardot require Salesforce CRM?$q$, $q$It is designed to integrate tightly with Salesforce Sales Cloud and delivers the most value alongside a Salesforce CRM license.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c2c65cc7-4f96-4e51-91e3-3da83872e2cd', $q$What is Pardot used for?$q$, $q$B2B marketing automation, including lead scoring, email nurture campaigns, landing pages and account-based marketing.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c2c65cc7-4f96-4e51-91e3-3da83872e2cd', $q$Who owns Pardot today?$q$, $q$Salesforce, which acquired it via ExactTarget in 2013 after ExactTarget acquired Pardot in 2012.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c2c65cc7-4f96-4e51-91e3-3da83872e2cd', $q$Is Pardot good for small businesses?$q$, $q$It is generally better suited to mid-market and enterprise B2B teams given its pricing and CRM dependency; smaller teams often consider HubSpot instead.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c2c65cc7-4f96-4e51-91e3-3da83872e2cd', $q$What are Pardot's main competitors?$q$, $q$HubSpot Marketing Hub, Adobe Marketo Engage, and Oracle Eloqua.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c2c65cc7-4f96-4e51-91e3-3da83872e2cd', $q$Sales and marketing alignment via ABM$q$, $q$Salesforce-native account-based marketing that keeps sales and marketing aligned on target accounts.$q$, $q$Enterprise B2B marketing and sales teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c2c65cc7-4f96-4e51-91e3-3da83872e2cd', $q$Lead nurturing and scoring$q$, $q$Automated multi-step nurture campaigns paired with lead scoring to prioritize outreach.$q$, $q$B2B demand generation teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c2c65cc7-4f96-4e51-91e3-3da83872e2cd', $q$Marketing ROI reporting$q$, $q$Attributing pipeline and revenue to campaigns directly inside Salesforce.$q$, $q$Marketing operations and RevOps teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c2c65cc7-4f96-4e51-91e3-3da83872e2cd', $q$Growth$q$, $q$$1,250/month$q$, $q$Billed annually$q$, NULL, $q$["Core email marketing","Lead scoring and grading","Landing pages and forms"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c2c65cc7-4f96-4e51-91e3-3da83872e2cd', $q$Plus$q$, $q$$2,500/month$q$, $q$Billed annually$q$, NULL, $q$["Advanced automation","Additional Salesforce integration features","Expanded reporting"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c2c65cc7-4f96-4e51-91e3-3da83872e2cd', $q$Advanced$q$, $q$$4,000/month$q$, $q$Billed annually$q$, NULL, $q$["AI-powered features","Expanded account-based marketing capabilities","Higher usage limits"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c2c65cc7-4f96-4e51-91e3-3da83872e2cd', $q$Premium$q$, $q$$15,000/month$q$, $q$Billed annually$q$, NULL, $q$["Highest usage limits","Most advanced automation and reporting features","Designed for large enterprises"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c2c65cc7-4f96-4e51-91e3-3da83872e2cd', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Pardot began in 2007 as an independent Atlanta-based marketing automation startup founded by David Cummings and Adam Blitzer. After being acquired by ExactTarget in 2012 and then becoming part of Salesforce in 2013 through Salesforce's acquisition of ExactTarget, Pardot grew into one of the most widely used B2B marketing automation platforms.$q$, $q$In April 2022, Salesforce officially renamed the product Marketing Cloud Account Engagement, though the platform's functionality, APIs and certifications were left unchanged. Many marketers, agencies and job listings still refer to the product as Pardot.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c2c65cc7-4f96-4e51-91e3-3da83872e2cd', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Pardot/MCAE's core capabilities include lead scoring and grading to prioritize which prospects sales should follow up with, automated email nurture campaigns built through a visual Engagement Studio, and customizable landing pages and forms for capturing leads without developer help.$q$, $q$Because it is native to the Salesforce ecosystem, it also supports account-based marketing features for targeting and reporting on named accounts, and ROI reporting that attributes pipeline and closed revenue back to specific marketing campaigns inside Salesforce.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c2c65cc7-4f96-4e51-91e3-3da83872e2cd', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Pardot/MCAE is priced on a subscription basis per organization (not per user), with four published tiers: Growth at $1,250/month, Plus at $2,500/month, Advanced at $4,000/month, and Premium at $15,000/month, all billed annually.$q$, $q$Optional add-ons include Salesforce Engage at $50/user/month for sales teams who want engagement alerts, and B2B Marketing Analytics Plus at roughly $3,000/month for deeper attribution and reporting dashboards.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3fda03d5-8efa-4417-bae1-e4cc14dc560a', $q$Flexible object data store$q$, $q$Schema-flexible data storage accessible via REST and GraphQL APIs.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3fda03d5-8efa-4417-bae1-e4cc14dc560a', $q$User authentication$q$, $q$Built-in user accounts, sessions and social login providers.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3fda03d5-8efa-4417-bae1-e4cc14dc560a', $q$Cloud Code functions$q$, $q$Run custom server-side logic without managing separate infrastructure.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3fda03d5-8efa-4417-bae1-e4cc14dc560a', $q$Push notifications$q$, $q$Send push notifications to iOS, Android and web clients.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3fda03d5-8efa-4417-bae1-e4cc14dc560a', $q$File storage$q$, $q$Store and serve files and media associated with app data.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3fda03d5-8efa-4417-bae1-e4cc14dc560a', $q$Self-hostable and vendor-neutral$q$, $q$Deploy on any infrastructure that supports Node.js, avoiding lock-in.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3fda03d5-8efa-4417-bae1-e4cc14dc560a', $q$Multi-platform SDKs$q$, $q$Official SDKs for iOS, Android, JavaScript, .NET, PHP and more.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3fda03d5-8efa-4417-bae1-e4cc14dc560a', $q$Free, MIT-licensed, and fully open source with no vendor lock-in$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3fda03d5-8efa-4417-bae1-e4cc14dc560a', $q$Mature codebase with roots going back to 2011 and continuous community development$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3fda03d5-8efa-4417-bae1-e4cc14dc560a', $q$Self-hostable on any infrastructure, useful for data-residency and compliance needs$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3fda03d5-8efa-4417-bae1-e4cc14dc560a', $q$Broad SDK support across major mobile and web platforms$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3fda03d5-8efa-4417-bae1-e4cc14dc560a', $q$Active community and managed hosting options such as Back4App for teams that don't want to self-host$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3fda03d5-8efa-4417-bae1-e4cc14dc560a', $q$No single company provides official commercial support for the open-source project itself$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3fda03d5-8efa-4417-bae1-e4cc14dc560a', $q$Requires ops and DevOps effort to self-host and maintain reliably at scale$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3fda03d5-8efa-4417-bae1-e4cc14dc560a', $q$Smaller mindshare today than Firebase or Supabase among new projects$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3fda03d5-8efa-4417-bae1-e4cc14dc560a', $q$Documentation and third-party tooling quality varies since it is community-maintained$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3fda03d5-8efa-4417-bae1-e4cc14dc560a', $q$Slower pace of major feature innovation than VC-backed competitors with dedicated product teams$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3fda03d5-8efa-4417-bae1-e4cc14dc560a', $q$Is Parse Platform still active in 2026?$q$, $q$Yes, it is maintained by an open-source community (parse-community) with ongoing releases, despite Facebook shutting down its original hosted service in 2017.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3fda03d5-8efa-4417-bae1-e4cc14dc560a', $q$Is Parse Platform free?$q$, $q$Yes, the core software is free and open source under the MIT license; commercial hosts may charge for managed hosting.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3fda03d5-8efa-4417-bae1-e4cc14dc560a', $q$Who created Parse?$q$, $q$Parse, Inc. was founded in 2011 by Tikhon Bernstam, Ilya Sukhar, James Yu and Kevin Lacker, and was acquired by Facebook in 2013.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3fda03d5-8efa-4417-bae1-e4cc14dc560a', $q$Why did Facebook open source Parse?$q$, $q$Facebook shut down its hosted Parse service in January 2017 and open-sourced the codebase so developers could migrate to self-hosted Parse Server instead of losing their backend entirely.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3fda03d5-8efa-4417-bae1-e4cc14dc560a', $q$Can I self-host Parse Server?$q$, $q$Yes, it runs on Node.js with MongoDB or PostgreSQL and can be deployed on your own infrastructure.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3fda03d5-8efa-4417-bae1-e4cc14dc560a', $q$What is Back4App's relationship to Parse Platform?$q$, $q$Back4App is a commercial hosting provider that offers managed Parse Server hosting and is a major sponsor of the open-source project.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3fda03d5-8efa-4417-bae1-e4cc14dc560a', $q$What are alternatives to Parse Platform?$q$, $q$Google Firebase, Supabase, AWS Amplify and PocketBase are commonly compared alternatives.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3fda03d5-8efa-4417-bae1-e4cc14dc560a', $q$Does Parse Platform support push notifications?$q$, $q$Yes, it includes built-in push notification support for iOS, Android and web.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3fda03d5-8efa-4417-bae1-e4cc14dc560a', $q$Self-hosted mobile app backend$q$, $q$Avoiding vendor lock-in with a self-hostable Firebase alternative for mobile apps.$q$, $q$Mobile app developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3fda03d5-8efa-4417-bae1-e4cc14dc560a', $q$Compliance-driven backend hosting$q$, $q$Organizations with data-residency requirements run their own backend infrastructure.$q$, $q$Regulated industries and enterprises$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3fda03d5-8efa-4417-bae1-e4cc14dc560a', $q$Rapid prototyping with an open-source BaaS$q$, $q$Spinning up a backend quickly for a new app idea without vendor lock-in.$q$, $q$Indie developers and startups building MVPs$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3fda03d5-8efa-4417-bae1-e4cc14dc560a', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full Parse Server codebase","Self-deployed on your own infrastructure","MIT licensed with no usage fees"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3fda03d5-8efa-4417-bae1-e4cc14dc560a', $q$Managed Hosting (via third parties)$q$, $q$Custom (varies by host, e.g. Back4App)$q$, $q$Varies by provider$q$, NULL, $q$["Managed Parse Server hosting","Scaling handled by the host","Support without self-hosting overhead"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3fda03d5-8efa-4417-bae1-e4cc14dc560a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Parse Platform began life as Parse, Inc., a startup founded in 2011 that offered mobile developers a hosted backend for data storage, authentication and push notifications. Facebook acquired the company in 2013 and ran it as a hosted service until announcing in January 2016 that it would shut down, effective January 28, 2017.$q$, $q$Instead of simply discontinuing the product, Facebook open-sourced the Parse Server codebase and client SDKs under the MIT license, allowing existing users to migrate to self-hosted deployments. Since 2016, Parse Platform has been maintained by an independent open-source community rather than a single company.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3fda03d5-8efa-4417-bae1-e4cc14dc560a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Parse Platform provides a schema-flexible object data store accessible through REST and GraphQL APIs, built-in user authentication with social login support, and Cloud Code functions for running custom server-side logic without standing up separate infrastructure.$q$, $q$It also includes push notification support for iOS, Android and web clients, file storage for media and attachments, and official SDKs across major platforms, all deployable on any infrastructure that supports Node.js with MongoDB or PostgreSQL.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3fda03d5-8efa-4417-bae1-e4cc14dc560a', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The core Parse Server software is completely free and open source under the MIT license, so self-hosting costs are limited to whatever infrastructure you run it on.$q$, $q$Teams that don't want to manage their own servers can use commercial managed-hosting providers such as Back4App, which offer their own paid pricing tiers for running Parse Server on their infrastructure.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3fda03d5-8efa-4417-bae1-e4cc14dc560a', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3fda03d5-8efa-4417-bae1-e4cc14dc560a', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('22f25c2f-1b4c-48c2-90e3-6d5df186e020', $q$Component cataloging$q$, $q$Track parts by category, footprint, manufacturer and multiple stock locations.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('22f25c2f-1b4c-48c2-90e3-6d5df186e020', $q$Pricing and stock tracking$q$, $q$Record price breaks and quantities across storage locations.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('22f25c2f-1b4c-48c2-90e3-6d5df186e020', $q$Datasheet and image attachments$q$, $q$Attach files and images directly to each part record.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('22f25c2f-1b4c-48c2-90e3-6d5df186e020', $q$Barcode and label generation$q$, $q$Generate and print barcodes and labels for parts and storage bins.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('22f25c2f-1b4c-48c2-90e3-6d5df186e020', $q$Project and BOM management$q$, $q$Group parts into projects with a bill of materials.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('22f25c2f-1b4c-48c2-90e3-6d5df186e020', $q$Granular permissions and two-factor authentication$q$, $q$Group-based permissions plus Google Authenticator and WebAuthn/U2F support.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('22f25c2f-1b4c-48c2-90e3-6d5df186e020', $q$Multi-language interface$q$, $q$Available in German, English, Russian, Japanese, French, Czech, Danish and Chinese.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('22f25c2f-1b4c-48c2-90e3-6d5df186e020', $q$Completely free and open source (AGPL-3.0) with no paid tiers$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('22f25c2f-1b4c-48c2-90e3-6d5df186e020', $q$Purpose-built for electronic component metadata, unlike generic inventory tools$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('22f25c2f-1b4c-48c2-90e3-6d5df186e020', $q$Supports multiple databases (MySQL, MariaDB, PostgreSQL, SQLite) and ships as a Docker image$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('22f25c2f-1b4c-48c2-90e3-6d5df186e020', $q$Strong permission system and two-factor authentication for shared or makerspace inventories$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('22f25c2f-1b4c-48c2-90e3-6d5df186e020', $q$Active multi-language support reflecting a strong European maker community$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('22f25c2f-1b4c-48c2-90e3-6d5df186e020', $q$Requires self-hosting and basic server administration skills; no official managed cloud version$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('22f25c2f-1b4c-48c2-90e3-6d5df186e020', $q$Interface and workflows are utilitarian, aimed at technical users rather than casual consumers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('22f25c2f-1b4c-48c2-90e3-6d5df186e020', $q$Smaller contributor base than larger open-source inventory projects, which can slow feature development$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('22f25c2f-1b4c-48c2-90e3-6d5df186e020', $q$No built-in e-commerce, procurement automation, or supplier API integrations out of the box$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('22f25c2f-1b4c-48c2-90e3-6d5df186e020', $q$Documentation is comprehensive but assumes familiarity with self-hosted web app deployment$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('22f25c2f-1b4c-48c2-90e3-6d5df186e020', $q$Is Part-DB free?$q$, $q$Yes, it is completely free and open source under the AGPL-3.0 license.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('22f25c2f-1b4c-48c2-90e3-6d5df186e020', $q$What is Part-DB used for?$q$, $q$Managing inventory of electronic components, including stock locations, pricing, datasheets and bills of materials.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('22f25c2f-1b4c-48c2-90e3-6d5df186e020', $q$Who maintains Part-DB?$q$, $q$It is primarily developed by Jan Bohmer (jbtronics) along with open-source contributors on GitHub.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('22f25c2f-1b4c-48c2-90e3-6d5df186e020', $q$Can I self-host Part-DB?$q$, $q$Yes, it runs on PHP/Symfony with MySQL, MariaDB, PostgreSQL or SQLite, and is also available as a Docker image.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('22f25c2f-1b4c-48c2-90e3-6d5df186e020', $q$Does Part-DB support barcodes?$q$, $q$Yes, it can generate and print barcodes and labels for parts and storage locations.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('22f25c2f-1b4c-48c2-90e3-6d5df186e020', $q$Is Part-DB good for makerspaces?$q$, $q$Yes, its group-based permissions system is designed for multiple users sharing a common inventory, such as hackerspaces.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('22f25c2f-1b4c-48c2-90e3-6d5df186e020', $q$What languages does Part-DB support?$q$, $q$At least eight, including German, English, Russian, Japanese, French, Czech, Danish and Chinese.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('22f25c2f-1b4c-48c2-90e3-6d5df186e020', $q$How is Part-DB different from InvenTree?$q$, $q$Both are open-source self-hosted inventory tools; Part-DB is more narrowly focused on electronic component metadata like footprints and datasheets, while InvenTree targets broader manufacturing and stock management.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('22f25c2f-1b4c-48c2-90e3-6d5df186e020', $q$Personal electronics parts inventory$q$, $q$Hobbyists track their own component stash across projects.$q$, $q$Electronics hobbyists and makers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('22f25c2f-1b4c-48c2-90e3-6d5df186e020', $q$Makerspace shared inventory$q$, $q$Multi-user, permissioned tracking of shared components across a hackerspace.$q$, $q$Hackerspaces and makerspaces$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('22f25c2f-1b4c-48c2-90e3-6d5df186e020', $q$Small hardware team component management$q$, $q$Tracking parts, BOMs and suppliers for small hardware builds.$q$, $q$Small electronics and hardware engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('22f25c2f-1b4c-48c2-90e3-6d5df186e020', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full Part-DB feature set","Self-deployed via Docker or a PHP/Symfony web server","AGPL-3.0 licensed"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('22f25c2f-1b4c-48c2-90e3-6d5df186e020', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Part-DB is a free, open-source inventory management system purpose-built for electronic components rather than general retail or warehouse stock. It is primarily developed by Jan Bohmer under the GitHub handle jbtronics, and the current server-based version is built on PHP and the Symfony framework.$q$, $q$The project is popular in the maker, hackerspace and small hardware-engineering communities, particularly in Europe, and is distributed both as source code you deploy on a web server and as a Docker image for simpler self-hosted setups.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('22f25c2f-1b4c-48c2-90e3-6d5df186e020', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Part-DB lets users catalog parts by category, footprint, manufacturer and multiple stock locations, attach datasheets and images to each part, and track price-break information across suppliers. Projects can group parts into a bill of materials (BOM) to track what a given build requires or has used.$q$, $q$The system includes barcode and label generation for parts and storage bins, a group-based permissions system with two-factor authentication (Google Authenticator and WebAuthn/U2F), and a responsive interface that works on desktop, tablet or phone, along with support for at least eight languages.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('22f25c2f-1b4c-48c2-90e3-6d5df186e020', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Part-DB has no commercial pricing tiers or paid plans. It is entirely free and open source under the AGPL-3.0 license, and there is no official managed cloud version.$q$, $q$The only costs involved are whatever server or hosting infrastructure a user chooses to run it on, since Part-DB must be self-hosted via PHP/Symfony or the provided Docker image.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('22f25c2f-1b4c-48c2-90e3-6d5df186e020', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('22f25c2f-1b4c-48c2-90e3-6d5df186e020', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b3922d4-da95-43dc-94df-57b5c18e296d', $q$Customizable animated invitations$q$, $q$Visually expressive, templated invite designs with animations and themes.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b3922d4-da95-43dc-94df-57b5c18e296d', $q$Text-first distribution$q$, $q$Share invites via text message or link; guests don't need to create an account.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b3922d4-da95-43dc-94df-57b5c18e296d', $q$RSVP and guest list management$q$, $q$Track who's coming, plus-ones, and send reminders automatically.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b3922d4-da95-43dc-94df-57b5c18e296d', $q$Group Order$q$, $q$Embedded shared shopping cart for party supplies via an Instacart partnership.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b3922d4-da95-43dc-94df-57b5c18e296d', $q$Photo sharing$q$, $q$Guests can upload and share event photos in one place.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b3922d4-da95-43dc-94df-57b5c18e296d', $q$Event updates and chat$q$, $q$Post updates and communicate with the full guest list from the event page.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b3922d4-da95-43dc-94df-57b5c18e296d', $q$Free for hosts and guests with no subscription cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b3922d4-da95-43dc-94df-57b5c18e296d', $q$Guests do not need to download an app or create an account to RSVP$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b3922d4-da95-43dc-94df-57b5c18e296d', $q$Highly visual, playful invitation designs popular with younger users$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b3922d4-da95-43dc-94df-57b5c18e296d', $q$Strong organic adoption and growth among Gen Z and millennial social circles$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6b3922d4-da95-43dc-94df-57b5c18e296d', $q$Group Order feature simplifies coordinating and paying for party supplies$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b3922d4-da95-43dc-94df-57b5c18e296d', $q$Monetization is still emerging and narrower than ticketing-based competitors like Eventbrite$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b3922d4-da95-43dc-94df-57b5c18e296d', $q$Not designed for large ticketed or commercial events$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b3922d4-da95-43dc-94df-57b5c18e296d', $q$Skews heavily toward a younger demographic, which may not fit all event types$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b3922d4-da95-43dc-94df-57b5c18e296d', $q$Group Order commerce feature currently depends on a single delivery partner (Instacart)$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b3922d4-da95-43dc-94df-57b5c18e296d', $q$Fewer enterprise or brand-event features compared to Eventbrite$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b3922d4-da95-43dc-94df-57b5c18e296d', $q$Is Partiful free?$q$, $q$Yes, creating and sending invitations and managing RSVPs is free for hosts and guests.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b3922d4-da95-43dc-94df-57b5c18e296d', $q$How does Partiful make money?$q$, $q$Primarily through Group Order, an add-on commerce feature for party supplies delivered via Instacart, rather than subscription fees.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b3922d4-da95-43dc-94df-57b5c18e296d', $q$Do guests need the Partiful app to RSVP?$q$, $q$No, invitations can be viewed and RSVP'd to via a shared link or text message without downloading the app or creating an account.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b3922d4-da95-43dc-94df-57b5c18e296d', $q$Who founded Partiful?$q$, $q$Shreya Murthy (CEO) and Joy Tao (CTO), who met at Palantir Technologies, founded the company in 2019.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b3922d4-da95-43dc-94df-57b5c18e296d', $q$How much funding has Partiful raised?$q$, $q$Approximately $27 million, including a $20 million Series A1 round led by Andreessen Horowitz in 2022.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b3922d4-da95-43dc-94df-57b5c18e296d', $q$Who is Partiful's typical user?$q$, $q$Primarily Gen Z and millennial users planning informal social gatherings; the majority of users are reportedly under 30.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b3922d4-da95-43dc-94df-57b5c18e296d', $q$Is Partiful similar to Evite?$q$, $q$Both are digital invitation tools, but Partiful emphasizes animated, playful designs and text-first sharing, while Evite has a more traditional, formal invitation format.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b3922d4-da95-43dc-94df-57b5c18e296d', $q$Can I sell tickets on Partiful?$q$, $q$Partiful is built for informal, free social gatherings rather than ticketed events; Eventbrite is better suited for ticketed events.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6b3922d4-da95-43dc-94df-57b5c18e296d', $q$Casual birthday and house parties$q$, $q$Creating and sending playful digital invites for informal gatherings.$q$, $q$Gen Z and millennial hosts$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6b3922d4-da95-43dc-94df-57b5c18e296d', $q$Group hangout coordination$q$, $q$Managing RSVPs, reminders and updates for informal social gatherings.$q$, $q$Friend groups and social circles$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6b3922d4-da95-43dc-94df-57b5c18e296d', $q$Party supply coordination$q$, $q$Using Group Order to collectively shop for party supplies ahead of an event.$q$, $q$Hosts organizing supplies for a gathering$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6b3922d4-da95-43dc-94df-57b5c18e296d', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Unlimited invitations","RSVP and guest list management","Photo sharing and event updates","Optional Group Order add-on for party supplies"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6b3922d4-da95-43dc-94df-57b5c18e296d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Partiful is a free event invitation app founded in 2019 by Shreya Murthy and Joy Tao, who met while working together at Palantir Technologies. Headquartered in New York, the company has grown rapidly among Gen Z and millennial users, becoming a go-to alternative for informal social event planning after the decline of Facebook Events.$q$, $q$The company has raised approximately $27 million in venture funding, including a $20 million round led by Andreessen Horowitz in 2022, and reported roughly 500,000 monthly active users in the first quarter of 2025, up 400% year over year.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6b3922d4-da95-43dc-94df-57b5c18e296d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Hosts build highly visual, animated digital invitations and share them via text message or a link, so guests can RSVP without downloading the app or creating an account. Each event has a single page for tracking RSVPs, sending reminders, posting updates, and sharing photos after the event.$q$, $q$Partiful's Group Order feature lets hosts create a shared shopping cart for party supplies through an Instacart partnership, giving guests or hosts an easy way to split costs and coordinate logistics for a gathering.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6b3922d4-da95-43dc-94df-57b5c18e296d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Partiful is entirely free for both hosts and guests, with no subscription fees for creating invitations, managing RSVPs, or using most of the app's features.$q$, $q$Instead of charging for the core product, Partiful monetizes through optional commerce add-ons, primarily Group Order, where it charges a delivery fee of around $5 and takes a percentage of the total order value through its Instacart partnership.$q$]::text[], 2);
